  const comment = await createComment(prompt.id, 'Original comment');

  await loginAsUser(page);
  await page.goto(`/prompts/${prompt.id}`);

  // Click reply
  await page.getByRole('button', { name: 'Reply' }).click();
  await page.getByPlaceholder('Write a reply').fill('Thanks for the feedback!');
  await page.getByRole('button', { name: 'Post Reply' }).click();

  // Should show threaded reply
  await expect(page.getByText('Thanks for the feedback!')).toBeVisible();
  await expect(page.getByTestId('reply-indent')).toBeVisible();
});
```

### 2. Comment Actions
```typescript
test('should edit own comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  await loginAsUser(page);
  const comment = await createComment(prompt.id, 'Original text', testUser.id);

  await page.goto(`/prompts/${prompt.id}`);

  // Edit comment
  await page.getByRole('button', { name: 'Edit' }).click();
  await page.getByRole('textbox').fill('Updated text');
