```

### 4. Comments Notifications
```typescript
test('should notify creator of new comment', async ({ page }) => {
  const prompt = await createPublicPrompt(creatorUser.id);

  // Other user adds comment
  await loginAs(page, otherUser);
  await page.goto(`/prompts/${prompt.id}`);
  await page.getByPlaceholder('Add a comment').fill('New comment here');
  await page.getByRole('button', { name: 'Post' }).click();

  // Check creator notifications
  await loginAs(page, creatorUser);
  await page.goto('/notifications');

  await expect(page.getByText(/commented on your prompt/i)).toBeVisible();
});
```

